urlset:
{%- for file in pages %}
  {%- if not file.page.is_link %}
    {%- set url = file.page.canonical_url if file.page.canonical_url else (config.site_url ~ file.page.url) %}

    {{ url | e }}
    {%- if file.page.meta and file.page.meta.git_revision_date_localized_raw_iso_date %}
    {{ file.page.meta.git_revision_date_localized_raw_iso_date }}
    {%- elif file.page.update_date %}
    {{ file.page.update_date }}
    {%- endif %}

  {%- endif %}
{%- endfor %}
